    const __m512d tw_W20_2_im = _mm512_set1_pd(W20_2_im);
    const __m512d tw_W20_3_re = _mm512_set1_pd(W20_3_re);
    const __m512d tw_W20_3_im = _mm512_set1_pd(W20_3_im);
    const __m512d tw_W20_4_re = _mm512_set1_pd(W20_4_re);
    const __m512d tw_W20_4_im = _mm512_set1_pd(W20_4_im);
    const __m512d tw_W20_6_re = _mm512_set1_pd(W20_6_re);
    const __m512d tw_W20_6_im = _mm512_set1_pd(W20_6_im);
    const __m512d tw_W20_8_re = _mm512_set1_pd(W20_8_re);
    const __m512d tw_W20_8_im = _mm512_set1_pd(W20_8_im);
    const __m512d tw_W20_9_re = _mm512_set1_pd(W20_9_re);
    const __m512d tw_W20_9_im = _mm512_set1_pd(W20_9_im);
