        __m512d t0r=_mm512_fnmadd_pd(cD,ss_r,x0_re), t0i=_mm512_fnmadd_pd(cD,ss_i,x0_im);
        x0_re=_mm512_add_pd(x0_re,ss_r); x0_im=_mm512_add_pd(x0_im,ss_i);
        __m512d p1r=_mm512_fmadd_pd(cA,_mm512_sub_pd(s1r,s2r),t0r), p1i=_mm512_fmadd_pd(cA,_mm512_sub_pd(s1i,s2i),t0i);
